code.C:
#include <stdio.h>
#include <stdlib.h>

// Define a struct for the linked list node
struct Node {
    int value;
    struct Node* next;
};

// Define a struct for the linked list
struct LinkedList {
    struct Node* head;
};

// Function to insert a node at the front of the linked list
void insert_front(struct LinkedList* list, int value) {
    printf("Inserting %d\n", value);

    // Step 1: Create a new Node
    struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
    if (new_node == NULL) {
        printf("Memory allocation failed\n");
        return;
    }
    new_node->value = value;

    // Step 2: Set next of new_node to the current head
    new_node->next = list->head;

    // Step 3: Set new_node as the head
    list->head = new_node;
}

// Function to get the value at the head of the linked list
int get_head_value(struct LinkedList* list) {
    if (list->head == NULL) {
        return -1;
    } else {
        return list->head->value;
    }
}

int main() {
    // Create an instance of LinkedList
    struct LinkedList list;
    list.head = NULL;

    insert_front(&list, 3);
    printf("The value at the head is: %d\n", get_head_value(&list));

    insert_front(&list, 2);
    printf("The value at the head is: %d\n", get_head_value(&list));

    return 0;
}

code.Java:
class Node {
    public int value;
    public Node next;

    // Constructor to initialize the node with a given value
    public Node(int val) {
        value = val;
        next = null;
    }
}

class LinkedList {
    public Node head;

    public void insertFront(int value) {
        System.out.println("Inserting " + value);

        // Step 1: Create a new Node
        Node newNode = new Node(value);

        // Step 2: Set next of newNode to the current head
        newNode.next = head;

        // Step 3: Set newNode as the head
        head = newNode;
    }

    public int getHeadValue() {
        if (head == null) {
            return -1;
        } else {
            return head.value;
        }
    }
}

public class Main {
    public static void main(String[] args) {
        LinkedList list = new LinkedList();
        list.insertFront(3);
        System.out.println("The value at the head is: " + list.getHeadValue());

        list.insertFront(2);
        System.out.println("The value at the head is: " + list.getHeadValue());
    }
}

